17→export function useWindow(options: UseWindowOptions = {}) {
18→  const onShowRef = useRef(options.onShow);
19→  const onHideRef = useRef(options.onHide);
20→
21→  useEffect(() => {
22→    onShowRef.current = options.onShow;
23→    onHideRef.current = options.onHide;
24→  });
25→
26→  useEffect(() => {
27→    if (!isTauri) return;
28→
29→    let unlisten: (() => void) | undefined;
30→    let cancelled = false;
31→
32→    (async () => {
33→      const { getCurrentWindow } = await import('@tauri-apps/api/window');
34→      const appWindow = getCurrentWindow();
35→
36→      const unlistenFocus = await appWindow.onFocusChanged(
37→        ({ payload: focused }) => {
38→          if (focused) {
39→            onShowRef.current?.();
40→          } else {
41→            onHideRef.current?.();
42→          }
43→        },
44→      );
