const { push } = nav;
const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
  useFavorites();

const handleTrayNavigate = useCallback(
  (target: string) => {
    const trayCommandMap: Record<
      string,
      {
        id: string;
        name: string;
      }
    > = {
      clipboard: {
        id: 'clipboard-history',
        name: 'Clipboard History',
      },
      snippets: {
        id: 'snippets',
        name: 'Snippets',
      },
      settings: {
        id: 'settings',
        name: 'Settings',
      },
    };

    const mapping = trayCommandMap[target];
    if (!mapping) return;

    const cmd = getCommand(mapping.id);
    if (!cmd?.component) return;

    nav.popToRoot();
    setQuery('');
    setSelectedIndex(0);
    setActionsOpen(false);
    setQuickLookOpen(false);
    setFilterValue('all');

    push(mapping.name, {
      type: 'command',
      commandId: mapping.id,
    });
  },
  [
    push,
    nav,
  ],

